const topic = $.input.topic;
const tone = $.input.tone || 'professional and engaging';
const wordCount = $.input.wordCount || 800;

let prompt = 'You are an expert blog writer and content strategist. Write a complete, publish-ready blog post.\n\n';
prompt += 'TOPIC: ' + topic + '\n';
prompt += 'TONE: ' + tone + '\n';
prompt += 'TARGET WORD COUNT: ' + wordCount + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Write an engaging title that is SEO-friendly\n';
prompt += '- Include an introduction, 3-5 main sections with headings, and a conclusion\n';
prompt += '- Use HTML formatting: <h2> for headings, <p> for paragraphs, <ul>/<li> for lists\n';
prompt += '- Include a meta description for SEO\n';
prompt += '- Add relevant tags (3-5 keywords)\n';
prompt += '- Make the content informative and original\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "title": "Blog Post Title",\n';
prompt += '  "content": "<p>Full HTML content...</p>",\n';
prompt += '  "excerpt": "Short excerpt for preview (1-2 sentences)",\n';
prompt += '  "metaDescription": "SEO meta description under 160 chars",\n';
prompt += '  "tags": ["tag1", "tag2"],\n';
prompt += '  "wordCount": 800,\n';
prompt += '  "readingTime": "4 min"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'Untitled Post', content: raw, excerpt: '', metaDescription: '', tags: [], wordCount: 0, readingTime: '0 min' }; }

const ai = $.steps.parseAI.output;
const wpResp = $.steps.publishToWordPress.response || {};
const wpData = wpResp.data || wpResp;
const now = new Date().toISOString().split('T')[0];
const postUrl = wpData.URL || wpData.url || wpData.short_URL || 'N/A';
const postId = wpData.ID || wpData.id || 'N/A';

return {
  date: now,
  title: ai.title || 'Untitled',
  url: postUrl,
  postId: String(postId),
  wordCount: String(ai.wordCount || 0),
  readingTime: ai.readingTime || 'N/A',
  status: 'published',
  tags: (ai.tags || []).join(', ')
};

const ai = $.steps.parseAI.output;
const row = $.steps.prepareSheetRow.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Blog Post Published!', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + (ai.title || 'Untitled') + '*' } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Word Count:*\n' + (ai.wordCount || 'N/A') },
  { type: 'mrkdwn', text: '*Reading Time:*\n' + (ai.readingTime || 'N/A') }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Tags:*\n' + (ai.tags || []).join(', ') },
  { type: 'mrkdwn', text: '*Status:*\n:white_check_mark: Published' }
] });

if (ai.excerpt) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Excerpt:*\n' + ai.excerpt.slice(0, 500) } });
}

if (row.url !== 'N/A') {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':link: <' + row.url + '|View Post>' } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI + WordPress + Google Sheets' }] });

const fallback = 'Published: ' + (ai.title || 'Blog Post') + ' - ' + row.url;
return { blocks, fallback };
